import { isHex, hexToU8a, isU8a } from '@polkadot/util';

class PayloadFilter {
    offset;
    pattern;
    constructor(pattern, offset = 0) {
        this.offset = offset;
        if (isHex(pattern)) {
            this.pattern = hexToU8a(pattern);
        }
        else if (isU8a(pattern)) {
            this.pattern = pattern;
        }
        else {
            throw new Error('Invalid pattern format');
        }
    }
    toJSON() {
        return {
            pattern: Array.from(this.pattern),
            offset: this.offset,
        };
    }
}

export { PayloadFilter };
